/* Test driver */
public class Main {
    public static void main(String[] args) {
        DocumentEditor ed = new DocumentEditor("doc");
        ed.insertText(0, "Hello");
        ed.insertText(5, " World");
        if (ed.getDocument().getFullText().equals("Hello World")) System.out.println("OK_INSERT");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        DocumentEditor ed = new DocumentEditor("doc");
        ed.insertText(0, "Hello");
        ed.insertText(5, " World");
        ed.undo();
        if (ed.getDocument().getFullText().equals("Hello")) {
            ed.redo();
            if (ed.getDocument().getFullText().equals("Hello World")) System.out.println("OK_UNDO_REDO");
        }
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        DocumentEditor ed = new DocumentEditor("doc");
        ed.insertText(0, "Hello");
        String v1 = ed.saveVersion("alice", "v1");
        ed.insertText(5, " World");
        ed.saveVersion("alice", "v2");
        ed.restoreVersion(v1);
        if (ed.getDocument().getFullText().equals("Hello")) System.out.println("OK_VERSION");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        DocumentEditor ed = new DocumentEditor("doc");
        ed.insertText(0, "Hello World");
        ed.formatText(0, 5, Formatting.Style.BOLD);
        boolean found = false;
        for (TextSegment s : ed.getDocument().getSegments()) {
            if (s.getFormatting().hasStyle(Formatting.Style.BOLD)) found = true;
        }
        if (found) System.out.println("OK_FORMAT");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        DocumentEditor ed = new DocumentEditor("doc");
        ed.insertText(0, "Hello World");
        Collaborator c = ed.addCollaborator("alice", "Alice");
        c.getCursor().moveTo(5);
        if (c.getCursor().getPosition() == 5 && c.getName().equals("Alice")) System.out.println("OK_COLLAB");
    }
}
